import { useState, useEffect, useRef } from "react";

const QUESTIONS = [
  {
    question: "Nechanchi yili tug'ilgansiz?",
    options: ["2005", "2006", "2007", "2008"],
    correct: 2,
  },
  {
    question: "Necha yoshsiz?",
    options: ["17", "18", "19", "20"],
    correct: 2,
  },
  {
    question: "Qanaqa taom yaxshi ko'rasiz?",
    options: ["Osh", "Manti", "Sushi", "Lag'mon"],
    correct: 2,
  },
  {
    question: "Qayerda o'qiysiz?",
    options: ["Maktabda", "Kollejda", "Universitetda", "Litseyda"],
    correct: 2,
  },
  {
    question: "Ukangizga nimangizni berasiz?",
    options: ["Telefon", "Soat", "iPad", "Naushnik"],
    correct: 2,
  },
  {
    question: "Otangizni ismi nima?",
    options: ["Botir", "G'ayrat", "Sardor", "Jasur"],
    correct: 1,
  },
  {
    question: "Onangizni ismi nima?",
    options: ["Dilnoza", "Malohat", "Nigora", "Zarina"],
    correct: 1,
  },
  {
    question: "Eng kichik ukangizni ismi nima?",
    options: ["Sardor", "Emron", "Jasur", "Aziz"],
    correct: 1,
  },
  {
    question: "Qaysi ukangiz dasturchi?",
    options: ["Jannatim ukam", "Shohruz", "Feruz", "Aziz"],
    correct: 0,
  },
  {
    question: "Qaysi ukangiz futbolchi?",
    options: ["Shohruz", "Feruz", "Jasur", "Aziz"],
    correct: 1,
  },
];

const RESULT_MESSAGES = [
  { maxMistakeRatio: 0, title: "MUKAMMAL! 🏆", text: "Bitta ham xato qilmading! Meni juda yaxshi bilar ekansan. Tug'ilgan kuning muborak bo'lsin! 🎂" },
  { maxMistakeRatio: 0.4, title: "Ajoyib! 🎉", text: "Deyarli hech qanday xatosiz topding!" },
  { maxMistakeRatio: 1, title: "Yomon emas! 🙂", text: "Bir necha joyda adashding, lekin baribir topding!" },
  { maxMistakeRatio: Infinity, title: "Harakat qiling! 😅", text: "Meni yaxshiroq bilib olishing kerak ekan 😉" },
];

function getResultMessage(mistakes, total) {
  const mistakeRatio = total > 0 ? mistakes / total : 0;
  return (
    RESULT_MESSAGES.find((r) => mistakeRatio <= r.maxMistakeRatio) ||
    RESULT_MESSAGES[RESULT_MESSAGES.length - 1]
  );
}

const MELODY = [
  [392.0, 0.28], [392.0, 0.22], [440.0, 0.5], [392.0, 0.5], [523.25, 0.5], [493.88, 1.0],
  [null, 0.12],
  [392.0, 0.28], [392.0, 0.22], [440.0, 0.5], [392.0, 0.5], [587.33, 0.5], [523.25, 1.0],
  [null, 0.12],
  [392.0, 0.28], [392.0, 0.22], [783.99, 0.5], [659.25, 0.5], [523.25, 0.5], [493.88, 0.5], [440.0, 1.0],
  [null, 0.12],
  [698.46, 0.28], [698.46, 0.22], [659.25, 0.5], [523.25, 0.5], [587.33, 0.5], [523.25, 1.0],
];

const WRONG_SOUND_SRC =
  "data:audio/mpeg;base64,";

const CORRECT_SOUND_SRC =
  "data:audio/mpeg;base64,";

const CONFETTI_COLORS = ["#F4B942", "#FF6B9D", "#7FD8BE", "#FDF6E3", "#B48EAD"];

function ConfettiPiece({ delay, left, color, rotate }) {
  return (
    <div
      className="confetti-piece"
      style={{
        left: `${left}%`,
        backgroundColor: color,
        animationDelay: `${delay}s`,
        transform: `rotate(${rotate}deg)`,
      }}
    />
  );
}

export default function BirthdayQuiz() {
  const [stage, setStage] = useState("intro"); 
  const [currentIndex, setCurrentIndex] = useState(0);
  const [locked, setLocked] = useState(false);
  const [score, setScore] = useState(0);
  const [confettiKey, setConfettiKey] = useState(0);
  const [blockedIndices, setBlockedIndices] = useState([]); 
  const [goneIndices, setGoneIndices] = useState([]); 
  const [hadMistake, setHadMistake] = useState(false); 
  const [mistakes, setMistakes] = useState(0); 
  const [singing, setSinging] = useState(false);

  const loopTimerRef = useRef(null);
  const playingRef = useRef(false);
  const uiCtxRef = useRef(null); 
  const melodyGainRef = useRef(null); 
  const wrongBufferRef = useRef(null); 
  const correctBufferRef = useRef(null); 

  const total = QUESTIONS.length;
  const current = QUESTIONS[currentIndex];

  const melodyDuration = MELODY.reduce((sum, [, dur]) => sum + dur, 0);

  function base64ToArrayBuffer(base64) {
    const binary = window.atob(base64);
    const len = binary.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) bytes[i] = binary.charCodeAt(i);
    return bytes.buffer;
  }

  function getUiCtx() {
    const Ctx = window.AudioContext || window.webkitAudioContext;
    if (!Ctx) return null;
    if (!uiCtxRef.current) {
      uiCtxRef.current = new Ctx();
    }
    if (uiCtxRef.current.state === "suspended") {
      uiCtxRef.current.resume().catch(() => {});
    }
    return uiCtxRef.current;
  }

  function decodeSoundInto(dataUri, targetRef) {
    try {
      const ctx = getUiCtx();
      if (!ctx) return;
      const raw = dataUri.split(",")[1] || dataUri;
      const arrayBuffer = base64ToArrayBuffer(raw);
      const maybePromise = ctx.decodeAudioData(
        arrayBuffer,
        (buf) => {
          targetRef.current = buf;
        },
        () => {

        }
      );
      if (maybePromise && typeof maybePromise.then === "function") {
        maybePromise
          .then((buf) => {
            targetRef.current = buf;
          })
          .catch(() => {});
      }
    } catch (e) {
    }
  }

  useEffect(() => {
    decodeSoundInto(WRONG_SOUND_SRC, wrongBufferRef);
    decodeSoundInto(CORRECT_SOUND_SRC, correctBufferRef);
  }, []);

  function playClickSound() {
    try {
      const ctx = getUiCtx();
      if (!ctx) return;
      const t = ctx.currentTime;
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.type = "square";
      osc.frequency.value = 950;
      osc.connect(gain);
      gain.connect(ctx.destination);
      gain.gain.setValueAtTime(0.0001, t);
      gain.gain.exponentialRampToValueAtTime(0.16, t + 0.008);
      gain.gain.exponentialRampToValueAtTime(0.0001, t + 0.05);
      osc.start(t);
      osc.stop(t + 0.06);
    } catch (e) {
    }
  }

  function playFailSound() {
    try {
      const ctx = getUiCtx();
      if (ctx && wrongBufferRef.current) {
        const src = ctx.createBufferSource();
        src.buffer = wrongBufferRef.current;
        src.connect(ctx.destination);
        src.start(0);
        return;
      }
    } catch (e) {

    }
    try {
      const ctx = getUiCtx();
      if (!ctx) return;
      const t = ctx.currentTime;
      const freqs = [311.13, 293.66, 233.08];
      freqs.forEach((f, i) => {
        const osc = ctx.createOscillator();
        const gain = ctx.createGain();
        osc.type = "sawtooth";
        osc.frequency.value = f;
        osc.connect(gain);
        gain.connect(ctx.destination);
        const start = t + i * 0.18;
        const dur = 0.24;
        gain.gain.setValueAtTime(0.0001, start);
        gain.gain.exponentialRampToValueAtTime(0.18, start + 0.02);
        gain.gain.exponentialRampToValueAtTime(0.0001, start + dur);
        osc.start(start);
        osc.stop(start + dur + 0.02);
      });
    } catch (e) {
    }
  }

  
  function playCorrectSynthFallback() {
    try {
      const ctx = getUiCtx();
      if (!ctx) return;
      const t = ctx.currentTime;

     
      const noiseDur = 0.02;
      const bufferSize = Math.max(1, Math.floor(ctx.sampleRate * noiseDur));
      const buffer = ctx.createBuffer(1, bufferSize, ctx.sampleRate);
      const data = buffer.getChannelData(0);
      for (let i = 0; i < bufferSize; i++) {
        data[i] = (Math.random() * 2 - 1) * (1 - i / bufferSize);
      }
      const noise = ctx.createBufferSource();
      noise.buffer = buffer;
      const bandpass = ctx.createBiquadFilter();
      bandpass.type = "bandpass";
      bandpass.frequency.value = 3200;
      bandpass.Q.value = 1.1;
      const noiseGain = ctx.createGain();
      noiseGain.gain.setValueAtTime(0.55, t);
      noiseGain.gain.exponentialRampToValueAtTime(0.001, t + noiseDur);
      noise.connect(bandpass);
      bandpass.connect(noiseGain);
      noiseGain.connect(ctx.destination);
      noise.start(t);
      noise.stop(t + noiseDur);

      const osc = ctx.createOscillator();
      const oscGain = ctx.createGain();
      osc.type = "triangle";
      osc.frequency.setValueAtTime(230, t + 0.004);
      osc.frequency.exponentialRampToValueAtTime(140, t + 0.035);
      oscGain.gain.setValueAtTime(0.0001, t + 0.004);
      oscGain.gain.exponentialRampToValueAtTime(0.24, t + 0.012);
      oscGain.gain.exponentialRampToValueAtTime(0.0001, t + 0.055);
      osc.connect(oscGain);
      oscGain.connect(ctx.destination);
      osc.start(t + 0.004);
      osc.stop(t + 0.06);
    } catch (e) {

    }
  }

  function playCorrectKeySound() {
    try {
      const ctx = getUiCtx();
      if (ctx && correctBufferRef.current) {
        const src = ctx.createBufferSource();
        const gain = ctx.createGain();
        src.buffer = correctBufferRef.current;
        src.connect(gain);
        gain.connect(ctx.destination);

        const t = ctx.currentTime;
        const maxDur = 2; 
        gain.gain.setValueAtTime(1, t);
        gain.gain.setValueAtTime(1, t + Math.max(0, maxDur - 0.15));
        gain.gain.linearRampToValueAtTime(0.0001, t + maxDur);

        src.start(0);
        src.stop(t + maxDur + 0.02);
        return;
      }
    } catch (e) {
      
    }
    playCorrectSynthFallback();
  }

  function stopMelody() {
    playingRef.current = false;
    if (loopTimerRef.current) {
      clearTimeout(loopTimerRef.current);
      loopTimerRef.current = null;
    }
    const ctx = uiCtxRef.current;
    const gainNode = melodyGainRef.current;
    if (ctx && gainNode) {
      const t = ctx.currentTime;
      try {
        gainNode.gain.cancelScheduledValues(t);
        gainNode.gain.setValueAtTime(gainNode.gain.value, t);
        gainNode.gain.linearRampToValueAtTime(0.0001, t + 0.04);
      } catch (e) {
      }
      setTimeout(() => {
        try {
          gainNode.disconnect();
        } catch (e) {
        }
      }, 70);
    }
    melodyGainRef.current = null; 
    setSinging(false);
  }

  function scheduleMelody(ctx) {
    const master = melodyGainRef.current;
    let t = ctx.currentTime + 0.05;
    for (const [freq, dur] of MELODY) {
      if (freq) {
        const osc = ctx.createOscillator();
        const gain = ctx.createGain();
        osc.type = "triangle";
        osc.frequency.value = freq;
        osc.connect(gain);
        gain.connect(master);
        const noteLen = dur * 0.92;
        gain.gain.setValueAtTime(0.0001, t);
        gain.gain.exponentialRampToValueAtTime(0.28, t + 0.03);
        gain.gain.setValueAtTime(0.28, t + noteLen * 0.6);
        gain.gain.exponentialRampToValueAtTime(0.0001, t + noteLen);
        osc.start(t);
        osc.stop(t + noteLen + 0.02);
      }
      t += dur;
    }
    loopTimerRef.current = setTimeout(() => {
      if (playingRef.current && uiCtxRef.current) {
        scheduleMelody(uiCtxRef.current);
      }
    }, melodyDuration * 1000 + 700);
  }

  function playMelody() {
    if (playingRef.current) return;
    try {
      const ctx = getUiCtx(); 
      if (!ctx) return;

  
      const master = ctx.createGain();
      master.gain.value = 1;
      master.connect(ctx.destination);
      melodyGainRef.current = master;

      playingRef.current = true;
      setSinging(true);
      scheduleMelody(ctx);
    } catch (e) {
    }
  }

  function toggleMelody() {
    playClickSound();
    if (playingRef.current) {
      stopMelody();
    } else {
      playMelody();
    }
  }

  useEffect(() => {
    if (stage === "result") {
      setConfettiKey((k) => k + 1);
      playMelody();
    } else {
      stopMelody();
    }
  }, [stage]);

  useEffect(() => {

    return () => {
      stopMelody();
      if (uiCtxRef.current) {
        uiCtxRef.current.close().catch(() => {});
        uiCtxRef.current = null;
      }
    };
  }, []);

  function startQuiz() {
    playClickSound();
    setStage("quiz");
    setCurrentIndex(0);
    setScore(0);
    setLocked(false);
    setBlockedIndices([]);
    setGoneIndices([]);
    setHadMistake(false);
    setMistakes(0);
  }

  function chooseOption(idx) {
    if (locked || blockedIndices.includes(idx)) return;

    if (idx === current.correct) {
      
      playCorrectKeySound();
      setLocked(true);
      setScore((s) => s + 1);
      setTimeout(() => {
        if (currentIndex + 1 < total) {
          setCurrentIndex((i) => i + 1);
          setLocked(false);
          setBlockedIndices([]);
          setGoneIndices([]);
          setHadMistake(false);
        } else {
          setStage("result");
        }
      }, 900);
    } else {
      
      playFailSound();
      setHadMistake(true);
      setMistakes((m) => m + 1);
      setBlockedIndices((prev) => [...prev, idx]);
      setTimeout(() => {
        setGoneIndices((prev) => [...prev, idx]);
      }, 480);
    }
  }

  function restart() {
    playClickSound();
    setStage("intro");
  }

  const resultMsg = getResultMessage(mistakes, total);

  return (
    <div className="bq-root">
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Fraunces:opsz,wght@9..144,500;9..144,700;9..144,900&family=Manrope:wght@400;500;600;700;800&display=swap');

        .bq-root {
          --ink: #FDF6E3;
          --night: #1B1B3A;
          --night-deep: #131229;
          --plum: #322B52;
          --gold: #F4B942;
          --coral: #FF6B9D;
          --mint: #7FD8BE;
          --muted: #B9B4D6;
          font-family: 'Manrope', sans-serif;
          background: radial-gradient(ellipse at 20% -10%, #3a2f63 0%, var(--night) 45%, var(--night-deep) 100%);
          color: var(--ink);
          min-height: 100vh;
          width: 100%;
          display: flex;
          align-items: center;
          justify-content: center;
          padding: 32px 16px;
          box-sizing: border-box;
          position: relative;
          overflow: hidden;
        }

        .bq-root * { box-sizing: border-box; }

        .bq-stars {
          position: absolute;
          inset: 0;
          background-image:
            radial-gradient(1.5px 1.5px at 10% 20%, rgba(255,255,255,0.5) 50%, transparent 100%),
            radial-gradient(1.5px 1.5px at 80% 10%, rgba(255,255,255,0.4) 50%, transparent 100%),
            radial-gradient(2px 2px at 60% 70%, rgba(255,255,255,0.35) 50%, transparent 100%),
            radial-gradient(1.5px 1.5px at 30% 85%, rgba(255,255,255,0.4) 50%, transparent 100%),
            radial-gradient(2px 2px at 90% 60%, rgba(255,255,255,0.3) 50%, transparent 100%),
            radial-gradient(1.5px 1.5px at 45% 40%, rgba(255,255,255,0.4) 50%, transparent 100%);
          pointer-events: none;
        }

        .bq-card {
          position: relative;
          width: 100%;
          max-width: 480px;
          background: linear-gradient(180deg, rgba(255,255,255,0.06), rgba(255,255,255,0.02));
          border: 1px solid rgba(244,185,66,0.18);
          border-radius: 28px;
          padding: 40px 32px;
          backdrop-filter: blur(6px);
          box-shadow: 0 30px 80px -20px rgba(0,0,0,0.6);
          z-index: 1;
        }

        .bq-eyebrow {
          font-family: 'Manrope', sans-serif;
          letter-spacing: 0.18em;
          text-transform: uppercase;
          font-size: 11px;
          color: var(--gold);
          font-weight: 700;
          margin-bottom: 14px;
          display: flex;
          align-items: center;
          gap: 8px;
        }

        .bq-eyebrow::before {
          content: '';
          width: 18px;
          height: 1px;
          background: var(--gold);
          display: inline-block;
        }

        .bq-title {
          font-family: 'Fraunces', serif;
          font-weight: 900;
          font-size: 34px;
          line-height: 1.1;
          margin: 0 0 14px;
          background: linear-gradient(135deg, #FDF6E3, #F4B942 60%, #FF6B9D);
          -webkit-background-clip: text;
          background-clip: text;
          color: transparent;
        }

        .bq-sub {
          color: var(--muted);
          font-size: 15px;
          line-height: 1.6;
          margin: 0 0 30px;
        }

        .bq-cake {
          font-size: 56px;
          text-align: center;
          margin-bottom: 18px;
          filter: drop-shadow(0 6px 18px rgba(244,185,66,0.35));
        }

        .bq-btn {
          width: 100%;
          border: none;
          cursor: pointer;
          border-radius: 16px;
          padding: 16px 20px;
          font-family: 'Manrope', sans-serif;
          font-weight: 700;
          font-size: 15px;
          letter-spacing: 0.01em;
          transition: transform 0.15s ease, box-shadow 0.15s ease;
        }

        .bq-btn:focus-visible {
          outline: 2px solid var(--gold);
          outline-offset: 3px;
        }

        .bq-btn-primary {
          background: linear-gradient(135deg, var(--gold), #e8a41a);
          color: #241a05;
          box-shadow: 0 10px 30px -8px rgba(244,185,66,0.55);
        }

        .bq-btn-primary:hover { transform: translateY(-2px); }

        .bq-candles {
          display: flex;
          gap: 8px;
          justify-content: center;
          margin-bottom: 28px;
          flex-wrap: wrap;
        }

        .bq-candle {
          width: 8px;
          height: 26px;
          border-radius: 3px;
          background: rgba(255,255,255,0.12);
          position: relative;
          transition: background 0.4s ease;
        }

        .bq-candle.lit {
          background: linear-gradient(180deg, var(--coral), var(--gold));
        }

        .bq-candle.lit::before {
          content: '';
          position: absolute;
          top: -10px;
          left: 50%;
          transform: translateX(-50%);
          width: 6px;
          height: 10px;
          border-radius: 50% 50% 50% 50% / 60% 60% 40% 40%;
          background: radial-gradient(circle, #fff7d6, var(--gold) 60%, transparent 100%);
          animation: flicker 1.1s ease-in-out infinite;
        }

        @keyframes flicker {
          0%, 100% { opacity: 1; transform: translateX(-50%) scale(1); }
          50% { opacity: 0.75; transform: translateX(-50%) scale(0.9); }
        }

        .bq-progress-label {
          text-align: center;
          font-size: 12px;
          color: var(--muted);
          letter-spacing: 0.08em;
          text-transform: uppercase;
          margin-bottom: 8px;
          font-weight: 700;
        }

        .bq-question {
          font-family: 'Fraunces', serif;
          font-size: 22px;
          font-weight: 700;
          line-height: 1.35;
          margin: 0 0 26px;
        }

        .bq-options {
          display: flex;
          flex-direction: column;
          gap: 10px;
        }

        .bq-option {
          text-align: left;
          padding: 14px 16px;
          border-radius: 14px;
          border: 1px solid rgba(255,255,255,0.14);
          background: rgba(255,255,255,0.04);
          color: var(--ink);
          font-family: 'Manrope', sans-serif;
          font-size: 14.5px;
          font-weight: 600;
          cursor: pointer;
          transition: all 0.15s ease;
          display: flex;
          align-items: center;
          gap: 10px;
          max-height: 300px;
        }

        .bq-option:hover:not(.locked) {
          border-color: var(--gold);
          background: rgba(244,185,66,0.08);
          transform: translateX(2px);
        }

        .bq-option:focus-visible {
          outline: 2px solid var(--gold);
          outline-offset: 2px;
        }

        .bq-option-letter {
          width: 24px;
          height: 24px;
          border-radius: 50%;
          background: rgba(255,255,255,0.08);
          display: flex;
          align-items: center;
          justify-content: center;
          font-size: 12px;
          flex-shrink: 0;
        }

        .bq-option.correct {
          border-color: var(--mint);
          background: rgba(127,216,190,0.14);
        }
        .bq-option.correct .bq-option-letter {
          background: var(--mint);
          color: #0d2b23;
        }

        .bq-option.wrong {
          border-color: var(--coral);
          background: rgba(255,107,157,0.12);
        }
        .bq-option.wrong .bq-option-letter {
          background: var(--coral);
          color: #3a0b1c;
        }

        .bq-option.flying {
          animation: flyAway 0.5s cubic-bezier(0.4, 0, 1, 1) forwards;
          pointer-events: none;
          cursor: default;
        }

        @keyframes flyAway {
          0% {
            transform: translateX(0) rotate(0deg) scale(1);
            opacity: 1;
          }
          100% {
            transform: translateX(140%) rotate(22deg) scale(0.8);
            opacity: 0;
          }
        }

        .bq-option.gone {
          animation: none;
          max-height: 0;
          padding-top: 0;
          padding-bottom: 0;
          margin: 0;
          border-width: 0;
          opacity: 0;
          transition: max-height 0.3s ease, padding 0.3s ease, margin 0.3s ease, border-width 0.3s ease;
          overflow: hidden;
        }

        .bq-hint {
          text-align: center;
          font-size: 13px;
          color: var(--muted);
          margin: 14px 0 0;
          font-weight: 600;
        }

        .bq-result-emoji {
          font-size: 60px;
          text-align: center;
          margin-bottom: 6px;
        }

        .bq-result-title {
          font-family: 'Fraunces', serif;
          font-size: 28px;
          font-weight: 800;
          text-align: center;
          margin: 0 0 10px;
        }

        .bq-result-text {
          text-align: center;
          color: var(--muted);
          font-size: 15px;
          line-height: 1.6;
          margin: 0 0 8px;
        }

        .bq-mistakes {
          text-align: center;
          color: var(--muted);
          font-size: 13px;
          margin: 0 0 4px;
        }

        .bq-mistakes strong {
          color: var(--coral);
          font-weight: 800;
        }

        .bq-score {
          text-align: center;
          font-family: 'Fraunces', serif;
          font-size: 46px;
          font-weight: 900;
          margin: 18px 0 24px;
          color: var(--gold);
        }

        .bq-score span {
          font-size: 20px;
          color: var(--muted);
          font-weight: 500;
        }

        .bq-mute-btn {
          position: absolute;
          top: 16px;
          right: 16px;
          width: 38px;
          height: 38px;
          border-radius: 50%;
          border: 1px solid rgba(244,185,66,0.3);
          background: rgba(255,255,255,0.06);
          color: var(--ink);
          font-size: 16px;
          display: flex;
          align-items: center;
          justify-content: center;
          cursor: pointer;
          transition: background 0.15s ease, transform 0.15s ease;
          z-index: 2;
        }

        .bq-mute-btn:hover {
          background: rgba(244,185,66,0.15);
          transform: scale(1.06);
        }

        .bq-mute-btn:focus-visible {
          outline: 2px solid var(--gold);
          outline-offset: 2px;
        }

        .bq-notes-row {
          display: flex;
          justify-content: center;
          gap: 14px;
          margin-top: 18px;
          font-size: 20px;
        }

        .bq-notes-row span {
          animation: noteBounce 1.1s ease-in-out infinite;
          opacity: 0.85;
        }

        .bq-notes-row span:nth-child(2) { animation-delay: 0.2s; }
        .bq-notes-row span:nth-child(3) { animation-delay: 0.4s; }

        @keyframes noteBounce {
          0%, 100% { transform: translateY(0); opacity: 0.6; }
          50% { transform: translateY(-8px); opacity: 1; }
        }

        .confetti-layer {
          position: fixed;
          inset: 0;
          pointer-events: none;
          overflow: hidden;
          z-index: 0;
        }

        .confetti-piece {
          position: absolute;
          top: -20px;
          width: 8px;
          height: 14px;
          opacity: 0.9;
          animation: fall 3.2s linear forwards;
        }

        @keyframes fall {
          to {
            top: 110%;
            transform: translateY(0) rotate(360deg);
          }
        }

        @media (prefers-reduced-motion: reduce) {
          .bq-candle.lit::before { animation: none; }
          .confetti-piece { animation: none; display: none; }
        }

        @media (max-width: 420px) {
          .bq-title { font-size: 27px; }
          .bq-card { padding: 30px 22px; border-radius: 22px; }
          .bq-question { font-size: 19px; }
        }
      `}</style>

      <div className="bq-stars" />

      {stage === "result" && (
        <div className="confetti-layer" key={confettiKey}>
          {Array.from({ length: 60 }).map((_, i) => (
            <ConfettiPiece
              key={i}
              delay={Math.random() * 1.5}
              left={Math.random() * 100}
              rotate={Math.random() * 360}
              color={CONFETTI_COLORS[i % CONFETTI_COLORS.length]}
            />
          ))}
        </div>
      )}

      <div className="bq-card">
        {stage === "intro" && (
          <>
            <div className="bq-eyebrow">Tug'ilgan kun testi</div>
            <div className="bq-cake">🎂</div>
            <h1 className="bq-title">Tug'ilgan kuningiz bilan!</h1>
            <p className="bq-sub">
              {total} ta savolga javob ber va bilamizmi-yo'qmi ko'ramiz. Har bir
              to'g'ri javob — bitta sham! 🕯️
            </p>
            <button className="bq-btn bq-btn-primary" onClick={startQuiz}>
              Testni boshlash →
            </button>
          </>
        )}

        {stage === "quiz" && current && (
          <>
            <div className="bq-progress-label">
              Savol {currentIndex + 1} / {total}
            </div>
            <div className="bq-candles">
              {QUESTIONS.map((_, i) => (
                <div
                  key={i}
                  className={`bq-candle ${i < currentIndex + (locked ? 1 : 0) ? "lit" : ""}`}
                />
              ))}
            </div>
            <h2 className="bq-question">{current.question}</h2>
            <div className="bq-options">
              {current.options.map((opt, idx) => {
                const isBlocked = blockedIndices.includes(idx);
                const isGone = goneIndices.includes(idx);
                let cls = "bq-option";
                if (locked) {
                  cls += " locked";
                  if (idx === current.correct) cls += " correct";
                }
                if (isBlocked) cls += " flying wrong";
                if (isGone) cls += " gone";
                return (
                  <button
                    key={idx}
                    className={cls}
                    onClick={() => chooseOption(idx)}
                    disabled={locked || isBlocked}
                  >
                    <span className="bq-option-letter">
                      {String.fromCharCode(65 + idx)}
                    </span>
                    {opt}
                  </button>
                );
              })}
            </div>
            {hadMistake && !locked && (
              <p className="bq-hint">Yana urinib ko'r — to'g'ri javobni top! 🔎</p>
            )}
          </>
        )}

        {stage === "result" && (
          <>
            <button
              className="bq-mute-btn"
              onClick={toggleMelody}
              aria-label={singing ? "Qo'shiqni o'chirish" : "Qo'shiqni yoqish"}
              title={singing ? "Qo'shiqni o'chirish" : "Qo'shiqni yoqish"}
            >
              {singing ? "🔊" : "🔇"}
            </button>

            <div className="bq-result-emoji">🎉</div>
            <h2 className="bq-result-title">{resultMsg.title}</h2>
            <div className="bq-score">
              {score}
              <span> / {total}</span>
            </div>
            <p className="bq-result-text">{resultMsg.text}</p>
            {mistakes > 0 && (
              <p className="bq-mistakes">
                Jami xato bosishlar: <strong>{mistakes}</strong> 🙈
              </p>
            )}

            {singing && (
              <div className="bq-notes-row" aria-hidden="true">
                <span>🎵</span>
                <span>🎶</span>
                <span>🎵</span>
              </div>
            )}

            <div style={{ marginTop: 18 }}>
              <button className="bq-btn bq-btn-primary" onClick={restart}>
                Qayta urinish 🔁
              </button>
            </div>
          </>
        )}
      </div>
    </div>
  );
}
